library(shiny)
library(dplyr)
library(DT)
library(stringr)

load("SmallVQR24.RData")

options(shiny.maxRequestSize = 100 * 1024^2)

# =========================
# Funzioni di supporto
# =========================

pos_norm_100 <- function(pos, denom) {
  case_when(
    is.na(denom) ~ NA_real_,
    denom == 1 ~ 1,
    TRUE ~ floor((pos - 1) / (denom - 1) * 99) + 1
  )
}

dt_style <- function(df, title = NULL) {
  DT::datatable(
    df,
    rownames = FALSE,
    class = "compact stripe hover",
    filter = "top",
    extensions = c("Buttons", "FixedHeader"),
    caption = if (!is.null(title)) tags$caption(
      style = "caption-side: top; text-align: left; font-weight: bold;",
      title
    ),
    options = list(
      dom = "Blrtip",
      buttons = c("copy", "csv", "excel"),
      scrollX = TRUE,
      pageLength = 30,
      lengthMenu = list(c(10, 30, 50, -1), c("10", "30", "50", "All")),
      autoWidth = TRUE,
      orderClasses = TRUE,
      fixedHeader = TRUE
    ),
    callback = JS("
      setTimeout(function() {
        table.columns.adjust().draw(false);
      }, 100);
    ")
  ) %>%
    formatStyle(
      columns = "R",
      backgroundColor = styleInterval(
        c(0.8, 0.9, 0.99, 1.1),
        c('red', 'orange', '#fff3b0', '#d9f2d9', '#2ca25f')
      )
    ) %>%
    formatStyle(
      columns = "POS_NORM_100",
      backgroundColor = styleInterval(
        c(25, 50, 75),
        c('#2ca25f', '#a1d99b', '#fdae6b', '#de2d26')
      ),
      color = "black"
    )
}

make_dt <- function(df, title = NULL, id_col, r_col, pos_col, extra_first = NULL, extra_name = NULL) {
  cols <- c(id_col, extra_first, r_col, pos_col)
  cols <- cols[!is.na(cols) & cols != ""]
  df2 <- df %>% dplyr::select(all_of(cols))
  
  names(df2)[names(df2) == id_col] <- "Rank"
  names(df2)[names(df2) == r_col] <- "R"
  names(df2)[names(df2) == pos_col] <- "POS_NORM_100"
  
  if (!is.null(extra_first) && extra_first != "" && !is.null(extra_name)) {
    names(df2)[names(df2) == extra_first] <- extra_name
  }
  
  dt_style(df2, title)
}

make_dt_3 <- function(df, title = NULL, id_col, r_col, iras_col, pos_col, gev_col, extra_first = NULL) {
  cols <- c(id_col, gev_col, extra_first, r_col, iras_col, pos_col)
  cols <- cols[!is.na(cols) & cols != ""]
  df2 <- df %>% dplyr::select(all_of(cols))
  
  names(df2)[names(df2) == id_col] <- "Rank"
  names(df2)[names(df2) == r_col] <- "R"
  names(df2)[names(df2) == iras_col] <- "IRD"
  names(df2)[names(df2) == pos_col] <- "POS_NORM_100"
  names(df2)[names(df2) == gev_col] <- "GEV"
  
  if (!is.null(extra_first) && extra_first != "") {
    names(df2)[names(df2) == extra_first] <- "Dipartimento"
  }
  
  dt_style(df2, title)
}

make_dt_4 <- function(df, title = NULL, id_col, r_col, gsd_col, pos_col, extra_first = NULL) {
