    sidebarLayout(
      sidebarPanel(width = 3, h4(textOutput("uni_label_3"))),
      mainPanel(
        tabsetPanel(
          tabPanel("Tab. 4.3 a+b", DTOutput("tab43")),
          tabPanel("Tab. 4.1 a", DTOutput("tab41")),
          tabPanel("Tab. 4.2 b", DTOutput("tab42"))
        )
      )
    )
  ),
  
  tabPanel(
    "Dipartimenti e GSD",
    sidebarLayout(
      sidebarPanel(width = 3, h4(textOutput("uni_label_4"))),
      mainPanel(
        tabsetPanel(
          tabPanel("Tab. 4.6 a+b", DTOutput("tab46")),
          tabPanel("Tab. 4.4 a", DTOutput("tab44")),
          tabPanel("Tab. 4.5 b", DTOutput("tab45"))
        )
      )
    )
  ),
  
  footer = tags$footer(
    class = "footer",
    tags$div(
      style = "max-width: 1200px; margin: 0 auto;",
      HTML("A. Irpino - DMF - Unicampania "),
      tags$a(
        href = "mailto:antonio.irpino@unicampania.it",
        "antonio.irpino@unicampania.it"
      ),
      HTML(" &nbsp;|&nbsp; Elaborazioni su dati VQR 2024 pubblicati qui: "),
      tags$a(
        href = "https://www.anvur.it/it/ricerca/qualita-della-ricerca/rapporti-di-valutazione/vqr-2020-2024",
        target = "_blank",
        rel = "noopener noreferrer",
        "AVA 2024 data"
      )
    )
  )
)

# =========================
# SERVER
# =========================

server <- function(input, output, session) {
  
  dati_uni <- reactive({
    req(input$uni)
    list(
      t33 = bound_by_sheet$`Tabella 3.3` %>% filter(Istituzione == input$uni),
      t31 = bound_by_sheet$`Tabella 3.1` %>% filter(Istituzione == input$uni),
      t32 = bound_by_sheet$`Tabella 3.2` %>% filter(Istituzione == input$uni),
      t36 = bound_by_sheet$`Tabella 3.6` %>% filter(Istituzione == input$uni),
      t34 = bound_by_sheet$`Tabella 3.4` %>% filter(Istituzione == input$uni),
      t35 = bound_by_sheet$`Tabella 3.5` %>% filter(Istituzione == input$uni),
      t39 = bound_by_sheet$`Tabella 3.9` %>% filter(Istituzione == input$uni),
      t37 = bound_by_sheet$`Tabella 3.7` %>% filter(Istituzione == input$uni),
      t38 = bound_by_sheet$`Tabella 3.8` %>% filter(Istituzione == input$uni),
      t43 = bound_by_sheet$`Tabella 4.3` %>% filter(Istituzione == input$uni),
      t41 = bound_by_sheet$`Tabella 4.1` %>% filter(Istituzione == input$uni),
      t42 = bound_by_sheet$`Tabella 4.2` %>% filter(Istituzione == input$uni),
      t46 = bound_by_sheet$`Tabella 4.6` %>% filter(Istituzione == input$uni),
      t44 = bound_by_sheet$`Tabella 4.4` %>% filter(Istituzione == input$uni),
      t45 = bound_by_sheet$`Tabella 4.5` %>% filter(Istituzione == input$uni)
    )
  })
  
  output$uni_label_1 <- renderText(input$uni)
  output$uni_label_2 <- renderText(input$uni)
  output$uni_label_3 <- renderText(input$uni)
  output$uni_label_4 <- renderText(input$uni)
  
  output$tab33 <- renderDT({
    tab33 <- dati_uni()$t33 %>%
      mutate(
        source_file = str_remove(source_file, "GEV"),
        R = `R (profilo a+b)`,
        POS_NORM_100 = pos_norm_100(`Pos. grad. compl.`, `Num. istituzioni compl.`),
        Rank = rank(-R, ties.method = "min")
      ) %>%
      transmute(Rank, GEV = source_file, R, IRAS = IRAS1_2x100, POS_NORM_100) %>%
      arrange(Rank)
    
    make_dt(tab33, "Tabella 3.3 - Profilo a+b", "Rank", "R", "POS_NORM_100", "GEV", "GEV")
  })
  
